using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using SourceGenerators;

namespace NsisPlugin.SourceGeneration.Export;

internal sealed class SharedEntryInitEmitter(SourceProductionContext context) : Emitter(context)
{
    private const string EntryInitHintName = "NsisPlugin.EntryInit.g.cs";
    private const string EntryInitSource =
        """
        // <auto-generated />

        namespace NsisPlugin.AutoGenerated
        {
            internal static class __NsisPluginExportEntryInit
            {
                public static void Invoke(global::System.IntPtr hwndParent, int string_size, global::System.IntPtr variables, global::System.IntPtr stacktop, global::System.IntPtr extra, global::NsisPlugin.NsEncoding encoding, string entryPoint, global::System.Action action)
                {
                    using var _ = global::NsisPlugin.NsPluginEnc.CreateEncScope(encoding);
                    global::NsisPlugin.NsPlugin.Init(hwndParent, string_size, variables, stacktop, extra);
                    try
                    {
                        action();
                    }
                    catch (global::System.Exception ex)
                    {
                        global::NsisPlugin.NsPlugin.StackTop.Push($"Exception in {entryPoint}: {ex}");
                    }
                }
            }
        }
        """;

    private const string EntryInitHelperRef = "global::NsisPlugin.AutoGenerated.__NsisPluginExportEntryInit";

    public void Emit(ImmutableEquatableArray<TypeGenerationSpec> types)
    {
        Context.AddSource(EntryInitHintName, EntryInitSource);

        foreach (var type in types)
        {
            var hintName = GetExportFileName(type);
            var sourceText = EmitExportTypeSource(type, WriteMembers);
            Context.AddSource(hintName, sourceText);
        }
        // 写入类成员
        static void WriteMembers(SourceWriter writer, TypeGenerationSpec typeSpec)
        {
            var callMethodNames = new Dictionary<string, int>(StringComparer.Ordinal);
            foreach (var methodSpec in typeSpec.Methods)
            {
                var callMethodName = WriteCall(writer, typeSpec.Type, methodSpec, callMethodNames);
                WriteExport(writer, methodSpec, callMethodName);
            }
        }
    }

    /// <summary>
    /// 写调用原方法的方法
    /// </summary>
    private static string WriteCall(SourceWriter writer, TypeRef containingType, MethodGenerationSpec methodSpec, Dictionary<string, int> callMethodNames)
    {
        // 调用原方法的方法名称
        var callName = $"{methodSpec.Name}_Call";
        if (!callMethodNames.TryGetValue(callName, out var index)) callMethodNames[callName] = 0;
        else
        {
            callMethodNames[callName] = ++index;
            callName = $"{callName}_{index}";
        }

        // 写入调用原方法的方法
        if (callMethodNames.Count > 1 || index != 0) writer.WriteLine();
        writer.WriteLine($"// Call the {methodSpec.Name} method");
        writer.WriteLine($"private static void {callName}()");
        writer.WriteLine('{');
        writer.Indentation++;
        // 方法内部
        {
            WriteInvocationAndReturn(writer, containingType, methodSpec);
        }
        writer.Indentation--;
        writer.WriteLine('}');
        return callName;
    }

    /// <summary>
    /// 写导出
    /// </summary>
    private static void WriteExport(SourceWriter writer, MethodGenerationSpec methodSpec, string callMethodName)
    {
        foreach (var actionSpec in methodSpec.Actions)
        {
            writer.WriteLine($"[{UnmanagedCallersOnlyAttributeRef}(EntryPoint = {SymbolDisplay.FormatLiteral(actionSpec.EntryPoint, true)}, CallConvs = new[] {{ typeof({CallConvCdeclRef}) }})]");
            writer.WriteLine($"public static void {actionSpec.EntryPoint}_Entry({IntPtrRef} hwndParent, {IntRef} string_size, {IntPtrRef} variables, {IntPtrRef} stacktop, {IntPtrRef} extra)");
            writer.WriteLine('{');
            writer.Indentation++;
            writer.WriteLine($"{EntryInitHelperRef}.Invoke(hwndParent, string_size, variables, stacktop, extra, {NsEncodingRef}.{actionSpec.Encoding}, {SymbolDisplay.FormatLiteral(actionSpec.EntryPoint, true)}, {callMethodName});");
            writer.Indentation--;
            writer.WriteLine('}');
        }
    }
}
